    background: @red;
  }
  &[overlay] {
    --bg-color: rgba(@base, var(--overlay-opacity));
    --bg-color-highlight: rgba(
      @base,
      max(0.4, calc(var(--overlay-opacity) * 1.2))
    );
    --text-shadow:
      -1px -1px 0px @base, 0px -1px 0px @base, 1px -1px 0px @base, -1px 0px
      0px @base, 1px 0px 0px @base, -1px 1px 0px @base, 0px 1px 0px @base,
      1px 1px 0px @base;
    --text-color: @text;
  }
  .resume-scroll {
    background-color: @surface0;
  }
}

@-moz-document domain("hyperpipe.surge.sh") {
  body {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  body[data-theme^="light"] {
    #catppuccin(@lightFlavor);
  }

  body[data-theme^="dark"],
  body[data-theme^="black"],
  body[data-theme^="dracula"],
  body[data-theme^="nord"] {
    #catppuccin(@darkFlavor);
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();

    --color-foreground: @accent !important;
    --color-background: @base !important;
    --color-background-soft: @surface0 !important;
    --color-background-mute: @surface1 !important;
    --color-border: @surface0 !important;
    --color-border-hover: @overlay0 !important;
    --color-shadow: @crust !important;
    --color-blur: fade(@mantle, 45%) !important;
    --color-gradient: linear-gradient(
      45deg,
      @accent,
      fade(@accent, 45%)
    );
    --color-scrollbar: @accent !important;
    --color-heading: @text !important;
    --color-text: @text !important;
  }
}

