&-link-title {
  position: relative;
  padding-left: 24px;
  padding-bottom: 19px;
  margin-top: -3px;
  line-height: 22px;
  -webkit-line-clamp: 2;

  &::before,
  &::after {
    content: '';
    position: absolute;
  }

  &::before {
    left: 0;
    top: 7px;
    display: block;
    width: 8px;
    height: 8px;
    border: 1px solid var(--tv-Anchor-dot-border-color);
    border-radius: 50%;
  }

  &::after {
    left: 3.5px;
    top: 19px;
    bottom: 0px;
    display: block;
    width: 1px;
    background-color: var(--tv-Anchor-line-bg-color);
    opacity: var(--tv-Anchor-line-opacity);
  }

  &--active:before {
    background-color: var(--tv-Anchor-dot-bg-color-active);
    border-color: var(--tv-Anchor-dot-border-color-active);
  }

  &:hover,
  &--active {
    color: var(--tv-Anchor-link-text-color-active);

    &:before {
      border-color: var(--tv-Anchor-dot-border-color-active);
      opacity: 1;
    }
  }
}

&.ql-bubble:not(.ql-disabled) {
  a {
    @apply relative;
    @apply whitespace-nowrap;

    &::before {
      background-color: #444;
      border-radius: 15px;
      top: -5px;
      @apply text-xs;
      @apply text-color-text-inverse;
      content: attr(href);
      @apply font-normal;
      @apply overflow-hidden;
      padding: 5px 15px;
      @apply no-underline;
      @apply ~'z-[1]';
    }

    &::after {
      border-top: 6px solid #444;
      border-left: 6px solid transparent;
      border-right: 6px solid transparent;
      @apply top-0;
      @apply ~"content-['']";
      @apply h-0;
      @apply w-0;
    }

    &::before,
    &::after {
      @apply left-0;
      @apply ~'ml-[50%]';
      @apply absolute;
      @apply ~'-translate-x-1/2' ~'-translate-y-full';
      transition: visibility 0s ease 200ms;
      @apply invisible;
    }

    &:hover::before,
    &:hover::after {
      @apply visible;
    }
  }
}

&__inner {
  display: block;
  width: 100%;
  min-height: 60px;
  min-height: calc(var(--tv-Textarea-height, 30px) * 2);
  color: var(--tv-Textarea-text-color);
  border: 1px solid var(--tv-Textarea-border-color);
  border-radius: var(--tv-Textarea-border-radius);
  background: var(--tv-Textarea-bg-color);
  padding: var(--tv-Textarea-padding-y) var(--tv-Textarea-padding-x);
  padding-bottom: var(--tv-Textarea-padding-bottom);
  line-height: 1.5;
  font-size: var(--tv-Textarea-font-size);
  resize: vertical;
  box-sizing: border-box;
  transition: border-color 0.2s cubic-bezier(0.645, 0.045, 0.355, 1);
  .placeholder(@color: var(--tv-Textarea-placeholder-text-color));

  &:hover {
    border-color: var(--tv-Textarea-inner-hover-border-color);
  }

  &:focus {
    border-color: var(--tv-Textarea-inner-active-border-color);
  }

  .@{textarea-prefix-cls}:has(&:focus) {
    border-color: var(--tv-Textarea-active-border-color);
  }

  &:hover,
  &:focus {
    outline: 0;
  }

  &.@{textarea-prefix-cls}__fix-height {
    min-height: 30px;
    height: 30px;
    padding: 0 8px;
    line-height: 30px;
    overflow: hidden;
  }
}

&__input-inner {
  width: 100%;
  height: var(--tv-Numeric-input-normal-height);
  line-height: 1.5; // 保证文本居中
  border: 1px solid var(--tv-Numeric-input-normal-border-color);
  border-radius: var(--tv-Numeric-input-border-radius);
  color: var(--tv-Numeric-input-normal-text-color);
  background: var(--tv-Numeric-input-normal-bg-color);
  font-size: var(--tv-Numeric-input-normal-font-size);
  padding: 0 calc(var(--tv-Numeric-input-icon-width) + 8px);
  outline: 0;
  display: inline-block;
  box-sizing: border-box;
  appearance: none;
  text-align: center;
  transition: border-color 0.2s cubic-bezier(0.645, 0.045, 0.355, 1);
  .placeholder(@color: var(--tv-Numeric-input-placeholder-text-color));

  &:hover {
    border: 1px solid var(--tv-Numeric-input-normal-active-border-color);
  }

  &:focus,
  &:active {
    border: 1px solid var(--tv-Numeric-input-border-color-active);
  }

